#include <stdio.h>
#include <string.h>
#define MAX 100005
#define LEN 8

int editDistance(char *s1, char *s2) {
    int dp[LEN + 1][LEN + 1];
    for (int i = 0; i <= LEN; i++) {
        dp[i][0] = i;
        dp[0][i] = i;
    }
    for (int i = 1; i <= LEN; i++) {
        for (int j = 1; j <= LEN; j++) {
            if (s1[i - 1] == s2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1];
            } else {
                dp[i][j] = 1 + (dp[i - 1][j] < dp[i][j - 1] ? dp[i - 1][j] : dp[i][j - 1]) < dp[i - 1][j - 1] ? (dp[i - 1][j] < dp[i][j - 1] ? dp[i - 1][j] : dp[i][j - 1]) : dp[i - 1][j - 1];
            }
        }
    }
    return dp[LEN][LEN];
}

int main() {
    int M, N;
    scanf("%d %d", &M, &N);
    char strings[N][LEN + 1];
    for (int i = 0; i < N; i++) {
        scanf("%s", strings[i]);
    }
    for (int i = 0; i < M; i++) {
        char query[LEN + 1];
        int d;
        scanf("%s %d", query, &d);
        int count = 0;
        for (int j = 0; j < N; j++) {
            if (editDistance(query, strings[j]) == d) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

