int editDistance(string s1, string s2) {
    int dp[LEN + 1][LEN + 1];
    for (int i = 0; i <= LEN; i++) {
        dp[i][0] = i;
        dp[0][i] = i;
    }
    for (int i = 1; i <= LEN; i++) {
        for (int j = 1; j <= LEN; j++) {
            if (s1[i - 1] == s2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1];
